# CsvReportGenerator.Tests.ps1
# Pester tests for the CSV Report Generator module.
# TDD approach: these tests were written FIRST, before the implementation.
# Each Describe block covers a distinct piece of functionality.

BeforeAll {
    # Import the module under test
    . "$PSScriptRoot/CsvReportGenerator.ps1"
}

# --- Test 1: CSV Import and Active Employee Filtering ---
# RED phase: We need a function that reads CSV and filters to active employees only.
Describe "Import-EmployeeCsv" {
    Context "when given a valid CSV file" {
        BeforeAll {
            $script:csvPath = "$PSScriptRoot/fixtures/employees.csv"
            $script:employees = Import-EmployeeCsv -Path $script:csvPath
        }

        It "should return only active employees" {
            # The fixture has 11 active and 3 inactive employees
            $script:employees | ForEach-Object {
                $_.status | Should -Be "active"
            }
        }

        It "should return the correct number of active employees" {
            $script:employees.Count | Should -Be 12
        }

        It "should parse salary as a numeric value" {
            $script:employees | ForEach-Object {
                $_.salary | Should -BeOfType [double]
            }
        }

        It "should parse hire_date as a DateTime" {
            $script:employees | ForEach-Object {
                $_.hire_date | Should -BeOfType [datetime]
            }
        }

        It "should preserve employee names" {
            $names = $script:employees | ForEach-Object { $_.name }
            $names | Should -Contain "Alice Johnson"
            $names | Should -Contain "Bob Smith"
            $names | Should -Not -Contain "Carol White"   # inactive
            $names | Should -Not -Contain "Frank Wilson"   # inactive
            $names | Should -Not -Contain "Karen Thomas"   # inactive
        }
    }

    Context "when given a non-existent file" {
        It "should throw a meaningful error" {
            { Import-EmployeeCsv -Path "nonexistent.csv" } | Should -Throw "*does not exist*"
        }
    }

    Context "when given an empty CSV (headers only)" {
        BeforeAll {
            $script:emptyPath = "$PSScriptRoot/fixtures/empty_employees.csv"
            "name,department,salary,hire_date,status" | Set-Content -Path $script:emptyPath
        }

        It "should return an empty collection" {
            $result = Import-EmployeeCsv -Path $script:emptyPath
            $result.Count | Should -Be 0
        }

        AfterAll {
            Remove-Item -Path $script:emptyPath -ErrorAction SilentlyContinue
        }
    }
}

# --- Test 2: Department Aggregates ---
# RED phase: We need functions to compute average salary and headcount by department.
Describe "Get-DepartmentAggregates" {
    BeforeAll {
        # Create mock employee data for predictable testing
        $script:mockEmployees = @(
            [PSCustomObject]@{ name = "A"; department = "Eng"; salary = [double]100000; hire_date = [datetime]"2020-01-01"; status = "active" }
            [PSCustomObject]@{ name = "B"; department = "Eng"; salary = [double]80000;  hire_date = [datetime]"2021-01-01"; status = "active" }
            [PSCustomObject]@{ name = "C"; department = "HR";  salary = [double]60000;  hire_date = [datetime]"2020-06-01"; status = "active" }
            [PSCustomObject]@{ name = "D"; department = "HR";  salary = [double]70000;  hire_date = [datetime]"2019-03-15"; status = "active" }
            [PSCustomObject]@{ name = "E"; department = "HR";  salary = [double]65000;  hire_date = [datetime]"2022-02-01"; status = "active" }
        )
        $script:aggregates = Get-DepartmentAggregates -Employees $script:mockEmployees
    }

    It "should return one entry per department" {
        $script:aggregates.Count | Should -Be 2
    }

    It "should compute correct average salary for each department" {
        $eng = $script:aggregates | Where-Object { $_.Department -eq "Eng" }
        $hr  = $script:aggregates | Where-Object { $_.Department -eq "HR" }
        $eng.AverageSalary | Should -Be 90000
        $hr.AverageSalary  | Should -BeApproximately 65000 0.01
    }

    It "should compute correct headcount for each department" {
        $eng = $script:aggregates | Where-Object { $_.Department -eq "Eng" }
        $hr  = $script:aggregates | Where-Object { $_.Department -eq "HR" }
        $eng.Headcount | Should -Be 2
        $hr.Headcount  | Should -Be 3
    }

    It "should sort departments alphabetically" {
        $script:aggregates[0].Department | Should -Be "Eng"
        $script:aggregates[1].Department | Should -Be "HR"
    }

    Context "when given an empty collection" {
        It "should return an empty collection" {
            $result = Get-DepartmentAggregates -Employees @()
            $result.Count | Should -Be 0
        }
    }
}

# --- Test 3: Overall Statistics ---
# RED phase: We need a function to compute overall statistics across all employees.
Describe "Get-OverallStatistics" {
    BeforeAll {
        $script:mockEmployees = @(
            [PSCustomObject]@{ name = "A"; department = "Eng"; salary = [double]100000; hire_date = [datetime]"2020-01-01"; status = "active" }
            [PSCustomObject]@{ name = "B"; department = "Eng"; salary = [double]80000;  hire_date = [datetime]"2021-01-01"; status = "active" }
            [PSCustomObject]@{ name = "C"; department = "HR";  salary = [double]60000;  hire_date = [datetime]"2020-06-01"; status = "active" }
        )
        $script:stats = Get-OverallStatistics -Employees $script:mockEmployees
    }

    It "should compute total headcount" {
        $script:stats.TotalHeadcount | Should -Be 3
    }

    It "should compute total salary" {
        $script:stats.TotalSalary | Should -Be 240000
    }

    It "should compute overall average salary" {
        $script:stats.AverageSalary | Should -Be 80000
    }

    It "should compute minimum salary" {
        $script:stats.MinSalary | Should -Be 60000
    }

    It "should compute maximum salary" {
        $script:stats.MaxSalary | Should -Be 100000
    }

    It "should compute number of departments" {
        $script:stats.DepartmentCount | Should -Be 2
    }

    Context "when given an empty collection" {
        It "should return zero values" {
            $result = Get-OverallStatistics -Employees @()
            $result.TotalHeadcount | Should -Be 0
            $result.TotalSalary | Should -Be 0
            $result.AverageSalary | Should -Be 0
            $result.DepartmentCount | Should -Be 0
        }
    }
