    }

    It "should include a title line" {
        $script:reportContent | Should -Match "Employee Summary Report"
    }

    It "should include department breakdown section" {
        $script:reportContent | Should -Match "Department Breakdown"
    }

    It "should include overall statistics section" {
        $script:reportContent | Should -Match "Overall Statistics"
    }

    It "should include each department's data" {
        $script:reportContent | Should -Match "Eng"
        $script:reportContent | Should -Match "HR"
    }

    It "should include headcount and average salary per department" {
        # Check that the report contains numeric values for the departments
        $script:reportContent | Should -Match "90,000"
        $script:reportContent | Should -Match "60,000"
    }

    It "should include overall totals" {
        $script:reportContent | Should -Match "3"      # total headcount
        $script:reportContent | Should -Match "80,000"  # average salary
