# --- Test 5: Export Report to File ---
# RED phase: We need a function that writes the report to a text file.
Describe "Export-SummaryReport" {
    BeforeAll {
        $script:mockEmployees = @(
            [PSCustomObject]@{ name = "A"; department = "Eng"; salary = [double]100000; hire_date = [datetime]"2020-01-01"; status = "active" }
            [PSCustomObject]@{ name = "B"; department = "HR";  salary = [double]60000;  hire_date = [datetime]"2020-06-01"; status = "active" }
        )
        $script:outputPath = "$PSScriptRoot/fixtures/test_report_output.txt"
    }

    It "should create the output file" {
        Export-SummaryReport -Employees $script:mockEmployees -OutputPath $script:outputPath
        Test-Path $script:outputPath | Should -Be $true
    }

    It "should write non-empty content to the file" {
        $content = Get-Content -Path $script:outputPath -Raw
        $content.Length | Should -BeGreaterThan 0
    }

    It "should contain the report title in the file" {
